import sys

class Solution:
    def shortestPath(self, n: int, edges: list[list[int]], s: int, t: int) -> int:
        from collections import deque
        adj = [[] for _ in range(n + 1)]
        indeg = [0] * (n + 1)
        for u, v, w in edges:
            adj[u].append((v, w))
            indeg[v] += 1
        # topological order
        q = deque([i for i in range(1, n + 1) if indeg[i] == 0])
        topo = []
        while q:
            u = q.popleft()
            topo.append(u)
            for v, _ in adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    q.append(v)
        INF = 10**19
        dist = [INF] * (n + 1)
        dist[s] = 0
        for u in topo:
            if dist[u] == INF:
                continue
            for v, w in adj[u]:
                if dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w
        return -1 if dist[t] == INF else dist[t]

