#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int shortestPath(int n, vector<vector<int>>& edges, int s, int t) {
        vector<vector<pair<int,long long>>> adj(n+1);
        vector<int> indeg(n+1,0);
        for (auto &e: edges) {
            int u=e[0], v=e[1]; long long w=e[2];
            adj[u].push_back({v,w});
            indeg[v]++;
        }
        queue<int> q;
        for (int i=1;i<=n;++i) if (indeg[i]==0) q.push(i);
        vector<int> topo;
        while(!q.empty()){
            int u=q.front();q.pop();
            topo.push_back(u);
            for(auto &pr: adj[u]){
                int v=pr.first;
                if(--indeg[v]==0) q.push(v);
            }
        }
        const long long INF = 4e18;
        vector<long long> dist(n+1, INF);
        dist[s]=0;
        for(int u: topo){
            if(dist[u]==INF) continue;
            for(auto &pr: adj[u]){
                int v=pr.first; long long w=pr.second;
                if(dist[u]+w < dist[v]) dist[v]=dist[u]+w;
            }
        }
        return dist[t]==INF ? -1 : (int)dist[t];
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n,m;
    if(!(cin>>n)) return 0;
    cin>>m;
    vector<vector<int>> edges;
    edges.reserve(m);
    for(int i=0;i<m;++i){
        int u,v,w;cin>>u>>v>>w;
        edges.push_back({u,v,w});
    }
    int s,t;cin>>s>>t;
    Solution sol;
    int ans = sol.shortestPath(n, edges, s, t);
    cout<<ans<<"\n";
    return 0;
}
